SELECT l_orderkey, SUM(l_extendedprice * (1.0 - l_discount)) as revenue, o_orderdate, o_shippriority FROM customer, orders, lineitem WHERE c_mktsegment = 'BUILDING' AND c_custkey = o_custkey AND o_orderdate < DATE '1995-03-15' AND l_orderkey = o_orderkey AND l_shipdate > DATE '1995-03-15' GROUP BY l_orderkey, o_orderdate, o_shippriority ORDER BY revenue DESC, o_orderdate ASC LIMIT 10;
